import React, { useEffect, useRef, useState } from "react";
import "dhtmlx-gantt/codebase/dhtmlxgantt.css";
import gantt from "dhtmlx-gantt";
import { useProjects } from "../../context/ProjectContext";

const Timeline = () => {
  const ganttContainer = useRef(null);
  const { projects, addProject } = useProjects();
  const [newProjectText, setNewProjectText] = useState("");

  useEffect(() => {
    gantt.config.xml_date = "%Y-%m-%d %H:%i";
    gantt.config.readonly = false;
    gantt.config.drag_move = true;
    gantt.config.drag_resize = true;
    gantt.config.drag_links = true;
    gantt.config.auto_scheduling = true;
    gantt.config.show_errors = false;
    gantt.config.highlight_critical_path = true;

    // Set Gantt chart background color
    gantt.config.grid_background = "#D0F0F4";
    gantt.config.chart_background = "#D0F0F4";

    gantt.init(ganttContainer.current);

    gantt.clearAll();
    gantt.parse({
      data: projects,
      links: [
        { id: 1, source: 1, target: 2, type: "0" },
        { id: 2, source: 2, target: 3, type: "0" },
        { id: 3, source: 3, target: 4, type: "0" },
        { id: 4, source: 4, target: 5, type: "0" },
      ],
    });

    // Apply background color to Gantt elements after initialization
    setTimeout(() => {
      const ganttGrid = document.querySelector(".gantt_grid");
      const ganttTask = document.querySelector(".gantt_task");
      if (ganttGrid) ganttGrid.style.backgroundColor = "#D0F0F4";
      if (ganttTask) ganttTask.style.backgroundColor = "#D0F0F4";
    }, 100);
  }, [projects]);

  const handleCreateProject = () => {
    if (!newProjectText.trim()) return;
    const newProject = {
      id: Date.now(),
      text: newProjectText,
      start_date: "2025-12-10 00:00",
      duration: 10,
      progress: 0,
    };
    addProject(newProject);
    setNewProjectText("");
  };

  const containerStyle = {
    margin: "30px auto",
    maxWidth: "1200px",
    borderRadius: "12px",
    boxShadow: "0 4px 20px rgba(0,0,0,0.1)",
    overflow: "hidden",
    backgroundColor: "#D0F0F4",
    fontFamily: "Segoe UI, sans-serif",
  };

  const headerStyle = {
    padding: "20px",
    background: "linear-gradient(to right, #4e54c8, #8f94fb)",
    color: "white",
    fontSize: "24px",
    fontWeight: "600",
    textAlign: "center",
    letterSpacing: "0.5px",
  };

  const inputContainerStyle = {
    padding: "20px",
    display: "flex",
    gap: "10px",
    backgroundColor: "#D0F0F4",
  };

  const inputStyle = {
    flex: 1,
    padding: "8px 12px",
    fontSize: "16px",
    border: "1px solid #ccc",
    borderRadius: "4px",
    backgroundColor: "white",
  };

  const buttonStyle = {
    padding: "8px 16px",
    backgroundColor: "#4e54c8",
    color: "white",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
    fontSize: "16px",
    fontWeight: "500",
  };

  const ganttStyle = {
    height: "600px",
    width: "100%",
    backgroundColor: "#D0F0F4",
  };

  return (
    <div style={containerStyle}>
      <div style={headerStyle}>📅 Project Timeline</div>
      <div style={inputContainerStyle}>
        <input
          type="text"
          value={newProjectText}
          onChange={(e) => setNewProjectText(e.target.value)}
          placeholder="New project name"
          style={inputStyle}
        />
        <button onClick={handleCreateProject} style={buttonStyle}>
          Add Project
        </button>
      </div>
      <div 
        ref={ganttContainer} 
        style={ganttStyle}
      ></div>
    </div>
  );
};

export default Timeline;
